let leftsearchSchema = [
    {
        fieldName: 'Search By Task Name',
        fieldType: "text",
        fieldIcon: "fa fa-wpforms",
        fieldSearchConditionName: [''],
        isSearch: false,
        paramName: "task_name",
        value: "",
        listOptions: []
    },
    {
        fieldName: 'Status',
        fieldType: "ddl-check",
        fieldIcon: "fa fa-list",
        fieldSearchConditionName: [''],
        isSearch: false,
        paramName: "status",
        value: "",
        listOptions: [],        
    }
];
let listActions=[  
    
]; 
async function bindleftCommonSearchdropdown(instance, moduleName, filtername) {
   // debugger
    var vm = instance;    
    if(filtername=='Status'){
        var params = `statusType=Category&hasglobal=true`;
        await DataService.GetStatusList(params).then(async (response) => {
            if (response.data.length > 0) { 
                const targetField = vm.leftSearchFields.find(field => field.fieldName === 'Status');
                if (targetField) {
                    targetField.listOptions = response.data.map(element => ({ name: element.STATUS, value: element.STATUS_ID }));
                }              
            }
        });
    }
};

export default { buttons, leftsearchSchema,listActions,bindleftCommonSearchdropdown};